def eprint(*args, **kwargs):
    print(*args, file=sys.stderr, **kwargs)


def parse_kv_list(items: Optional[List[str]]) -> Dict[str, str]:
    if not items:
        return {}
    out: Dict[str, str] = {}
    for it in items:
        if "=" not in it:
            raise ValueError(f"Invalid key=value item: {it}")
        k, v = it.split("=", 1)
        k = k.strip()
        v = v.strip()
        if not k:
            raise ValueError(f"Invalid empty key in item: {it}")
        out[k] = v
    return out


def parse_topics_list(topics: Optional[List[str]]) -> List[str]:
    if not topics:
        return []
    out: List[str] = []
    for t in topics:
        if not t:
            continue
        for part in t.split(","):
            part = part.strip()
            if part:
                out.append(part)
    # de-dup preserve order
    seen = set()
    dedup = []
    for t in out:
        if t not in seen:
            dedup.append(t)
            seen.add(t)
    return dedup


def parse_topics_json(path: Optional[str]) -> List[dict]:
    if not path:
        return []
    with open(path, "r", encoding="utf-8") as f:
        data = json.load(f)
    if isinstance(data, dict):
        # allow {"topics":[...]} or {"name":...}
        if "topics" in data:
            data = data["topics"]
        else:
            data = [data]
    if not isinstance(data, list):
        raise ValueError("Topics JSON must be a list or object containing 'topics' list.")
    for obj in data:
        if not isinstance(obj, dict) or "name" not in obj:
            raise ValueError("Each topic JSON entry must be an object with at least a 'name' field.")
    return data


def parse_int(value: Optional[str], name: str) -> Optional[int]:
    if value is None:
        return None
    try:
        return int(value)
    except Exception as ex:
        raise ValueError(f"Invalid {name}: {value}") from ex


def validate_topic_name(name: str) -> None:
    # Kafka allows more than this; keep it permissive but prevent obvious issues
    if len(name) == 0 or len(name) > 249:
        raise ValueError(f"Invalid topic name length: {name!r}")
    if re.search(r"\s", name):
        raise ValueError(f"Invalid topic name (contains whitespace): {name!r}")


