def describe_topics(admin: KafkaAdminClient, topics: List[str]) -> int:
    for t in topics:
        validate_topic_name(t)
    md = admin._client.cluster
    # Force metadata update
    admin._client.poll(timeout_ms=1000)
    admin._client.cluster.request_update()
    admin._client.poll(timeout_ms=1000)

    # kafka-python lacks a clean public describe topics API in AdminClient
    # We'll provide basic existence + partition counts via metadata if available
    result = {}
    for t in topics:
        p = md.partitions_for_topic(t)
        if p is None:
            result[t] = {"exists": False}
        else:
            result[t] = {"exists": True, "partitions": len(p)}
    print(json.dumps({"action": "describe-topics", "result": result}, indent=2, sort_keys=True))
    return 0


def build_topic_specs_from_args(args) -> List[TopicSpec]:
    specs: List[TopicSpec] = []
    base_configs = parse_kv_list(args.config) if hasattr(args, "config") else {}
    base_partitions = getattr(args, "partitions", None)
    base_replication = getattr(args, "replication_factor", None)

    json_specs = parse_topics_json(getattr(args, "topics_json", None))
    cli_topics = parse_topics_list(getattr(args, "topics", None))

    if json_specs:
        for obj in json_specs:
            name = obj["name"]
            validate_topic_name(name)
            partitions = obj.get("partitions", base_partitions)
            replication = obj.get("replication_factor", obj.get("replicas", base_replication))
            cfg = dict(base_configs)
            cfg.update(obj.get("configs", {}) or {})
            specs.append(
                TopicSpec(
                    name=name,
                    partitions=partitions,
                    replication_factor=replication,
                    configs=cfg,
                )
            )
    elif cli_topics:
        for name in cli_topics:
            validate_topic_name(name)
            specs.append(
                TopicSpec(
                    name=name,
                    partitions=base_partitions,
                    replication_factor=base_replication,
                    configs=dict(base_configs),
                )
            )
    else:
        raise ValueError("No topics specified. Use --topics and/or --topics-json.")

    return specs


def add_common_args(p: argparse.ArgumentParser) -> None:
    p.add_argument("--bootstrap-servers", required=True, help="Kafka bootstrap servers, e.g. host1:9092,host2:9092")
    p.add_argument("--client-id", default="kafka-admin-script")
